using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e5+5;
int n,m,b,c;
int trie[MAXN][5],idx=0,cnt[MAXN],ed[MAXN];
void insert(string s)
{
	int p=0,len=s.size()-1;
	FOR(i,0,len)
	{
		int x=s[i]-'0';
		if(!trie[p][x])trie[p][x]=++idx;
		p=trie[p][x];
		++cnt[p];
	}
	ed[p]++;
}
int find(string s)
{
	int p=0,ans=0,len=s.size()-1;
	FOR(i,0,len)
	{
		int x=s[i]-'0';
		if(!trie[p][x])return ans;
		p=trie[p][x];
		ans+=ed[p];
	}
	return ans-ed[p]+cnt[p];
}
